verb :moveto(target) rx {
  // Restrict $outline_item to outliners and $nowhere (recycle). Reject
  // any attempt to move into an actor's inventory, a room, or another
  // non-outliner container; this is what makes the class not-carryable.
  // Cross-outliner moves are allowed for the item owner, source-outliner
  // owner, or wizard.
  if (target == $nowhere) {
    moveto(this, target);
    return true;
  }
  if (!isa(target, $outliner)) {
    raise { code: "E_NOT_PORTABLE", message: "outline items can only live in an $outliner", value: { item: this, target: target } };
  }
  let here = location(this);
  if (here != target && isa(here, $outliner)) {
    let allowed = false;
    if (this.owner == actor) { allowed = true; }
    if (here.owner == actor) { allowed = true; }
    if (has_flag(actor, "wizard")) { allowed = true; }
    if (!allowed) {
      raise { code: "E_PERM", message: "only the item owner, source outliner owner, or a wizard can move an item across outliners", value: { item: this, from: here, to: target } };
    }
  }
  moveto(this, target);
  return true;
}

verb :recycle() rx {
  // Defensive cleanup: substrate recycle does not fire :exitfunc, so a
  // direct recycle(item) would otherwise leave children pointing at a
  // tombstoned .parent. Detach from the containing outliner first.
  let here = location(this);
  if (isa(here, $outliner)) {
    try { here:_detach_item(this, { emit: true, clear_item: true }); } except err { }
  }
  return true;
}

verb :set_hidden(hidden) rx {
  if (typeof(hidden) != "boolean") {
    if (hidden == 0) { hidden = false; }
    else { if (hidden == 1) { hidden = true; } else { raise { code: "E_INVARG", message: "set_hidden requires a boolean", value: hidden }; } }
  }
  let here = location(this);
  let allowed = false;
  if (isa(here, $outliner)) {
    let actor_loc = location(actor);
    if (actor_loc == here) { allowed = true; }
  }
  if (this.owner == actor) { allowed = true; }
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (!allowed) { raise { code: "E_PERM", message: "cannot toggle hidden on this item", value: this }; }
  this.hidden = hidden;
  return true;
}

verb :look_self() rxd {
  let items = this:list_items();
  let n = length(items);
  let summary = this.name + " has " + to_string(n) + " item";
  if (n != 1) { summary = summary + "s"; }
  summary = summary + ".";
  let focus = null;
  let key = to_string(actor);
  let fmap = this.focus_by_actor;
  if (has(fmap, key)) { focus = fmap[key]; }
  return { id: this, title: this.name, description: this.description, summary: summary, item_count: n, items: items, roster: this:room_roster(), focus: focus };
}

verb :room_roster() rxd {
  // Adapt the compact owner projection without dereferencing actor clusters.
  let rows = [];
  for compact in room_roster(this) {
    let row = { id: compact["player"], name: compact["name"], presence: compact["presence"] };
    if (compact["idle_seconds"] != null) { row["idle_seconds"] = compact["idle_seconds"]; }
    rows = rows + [row];
  }
  return rows;
}

verb :enterfunc(object) rx {
  if (isa(object, $actor)) {
    // Visit-scoped editing state is reset by movement, but absence already means
    // root focus / no undo. Avoid no-op shared-map writes on ordinary entry.
    let key = to_string(object);
    let fmap = this.focus_by_actor;
    if (has(fmap, key) && fmap[key] != null) {
      fmap[key] = null;
      this.focus_by_actor = fmap;
    }
    let umap = this.last_undo;
    if (has(umap, key)) {
      let next = {};
      for k in keys(umap) { if (k != key) { next[k] = umap[k]; } }
      this.last_undo = next;
    }
    let text = object.name + " opens " + this.name + ".";
    observe({ type: "outliner_entered", source: this, actor: object, outliner: this, origin: this.mount_room, text: text, ts: now() });
    if (this.mount_room != null) {
      observe_to_space(this.mount_room, { type: "outliner_activity", source: this.mount_room, outliner: this, actor: object, text: text, ts: now() });
    }
    return true;
  }
  // Items no longer self-place on enter: add_item / move_item / _restore_item
  // own edge placement and emit the observation. The edge index is the sole
  // structural authority, so a physical enter is a no-op for items.
  return true;
}

verb :exitfunc(object) rx {
  if (isa(object, $actor)) {
    // Entry and user mutations clean up visit-scoped focus/undo maps. Exit stays
    // observation-only to avoid shared-map conflicts during cross-scope moves.
    let text = object.name + " closes " + this.name + ".";
    observe({ type: "outliner_left", source: this, actor: object, outliner: this, destination: this.mount_room, text: text, ts: now() });
    if (this.mount_room != null) {
      observe_to_space(this.mount_room, { type: "outliner_activity", source: this.mount_room, outliner: this, actor: object, text: text, ts: now() });
    }
    return true;
  }
  if (isa(object, $outline_item)) {
    this:_detach_item(object, { emit: true, clear_item: true });
  }
  return true;
}

verb :list_items() rxd {
  // Edge-based whole-tree read: object_tree_rows derives the tree shape and
  // each row's index from the items' `__ordered_edge` { parent, rank } cells
  // (fractional-rank order), never from separate parent/position props.
  return object_tree_rows(this, $outline_item, "__ordered_edge", "text", "hidden");
}

verb :_detach_item(item, opts) rx {
  if (typeof(opts) != "map") { opts = {}; }
  let emit = true;
  if (has(opts, "emit")) { emit = opts["emit"]; }
  let clear_item = true;
  if (has(opts, "clear_item")) { clear_item = opts["clear_item"]; }
  // Former parent from the leaving item's own edge.
  let e = item.__ordered_edge; let former_parent = null;
  if (typeof(e) == "map") { former_parent = e["parent"]; }
  // Re-home DIRECT children to former_parent, appended after its current
  // siblings — one edge rewrite per direct child (bounded to direct children).
  let kids = ordered_children(item);
  let base = ordered_children(former_parent);
  let last = null;
  if (length(base) > 0) { last = base[length(base)]["rank"]; }
  for kr in kids {
    let kid = kr["child"];
    let nr = rank_between(last, null);
    kid.__ordered_edge = { parent: former_parent, rank: nr };
    last = nr;
  }
  if (clear_item) {
    // Detach the leaving item itself (empty rank = no effective edge).
    item.__ordered_edge = { parent: null, rank: "" };
  }
  if (emit) {
    observe({ type: "outline_item_removed", source: this, actor: actor, outliner: this, item: item, reparented_to: former_parent, ts: now() });
  }
  return true;
}

verb :_set_undo(actor_obj, record) rx {
  let key = to_string(actor_obj);
  let umap = this.last_undo;
  let next = {};
  // Prune against the owner-authoritative roster, never one shard's actors.
  let present_keys = {};
  for compact in room_roster(this) { present_keys[to_string(compact["player"])] = true; }
  for k in keys(umap) {
    if (k != key && has(present_keys, k)) { next[k] = umap[k]; }
  }
  next[key] = record;
  this.last_undo = next;
  return true;
}

verb :_restore_item(state, _no_store) rx {
  if (typeof(state) != "map") { raise { code: "E_INVARG", message: "_restore_item requires a state map", value: state }; }
  let parent_id = null;
  if (has(state, "parent_id")) { parent_id = state["parent_id"]; }
  if (parent_id != null) {
    if (!isa(parent_id, $outline_item) || location(parent_id) != this || is_recycled(parent_id)) { parent_id = null; }
  }
  let writers = [];
  if (has(state, "writers")) {
    for w in state["writers"] {
      if (!is_recycled(w)) { writers = writers + [w]; }
    }
  }
  let item_name = "";
  if (has(state, "name")) { item_name = state["name"]; }
  let item_desc = "";
  if (has(state, "description")) { item_desc = state["description"]; }
  let item_owner = actor;
  if (has(state, "owner")) {
    if (!is_recycled(state["owner"])) { item_owner = state["owner"]; }
  }
  let body = "";
  if (has(state, "text")) { body = state["text"]; }
  let hidden = false;
  if (has(state, "hidden")) { hidden = state["hidden"]; }
  let captured_index = 0;
  if (has(state, "index")) { captured_index = state["index"]; }
  let item = create($outline_item, { owner: item_owner, name: item_name, description: item_desc, location: this });
  // Insert at the captured index under parent_id via one fractional edge.
  let rows = ordered_children(parent_id);
  let n = length(rows);
  let idx = captured_index;
  if (typeof(idx) != "number") { idx = n; }
  idx = floor(idx);
  if (idx < 0) { idx = 0; }
  if (idx > n) { idx = n; }
  let lo = null; let hi = null;
  if (idx > 0) { lo = rows[idx]["rank"]; }
  if (idx < n) { hi = rows[idx + 1]["rank"]; }
  item.__ordered_edge = { parent: parent_id, rank: rank_between(lo, hi) };
  item:set_hidden(hidden);
  for w in writers { item:add_writer(w); }
  item:set_text(body);
  // Restore captured children under the new item at their captured indices.
  if (has(state, "children")) {
    let kid_idx = 0;
    for entry in state["children"] {
      let kid = entry["item"];
      if (!is_recycled(kid)) {
        if (isa(kid, $outline_item)) {
          try { this:move_item(kid, item, kid_idx, true); } except err { }
        }
      }
      kid_idx = kid_idx + 1;
    }
  }
  if (!_no_store) {
    this:_set_undo(actor, { verb: "remove_item", args: [item] });
  }
  return item;
}

verb :add_item(text, parent_id, index, _no_store) rx {
  if (typeof(text) != "string") { raise { code: "E_INVARG", message: "add_item requires text", value: text }; }
  if (text == "") { raise { code: "E_INVARG", message: "add_item requires non-empty text", value: text }; }
  // Default parent: caller's focus when parent_id is null.
  let p = parent_id;
  if (p == null) {
    let key = to_string(actor);
    let fmap = this.focus_by_actor;
    if (has(fmap, key)) { p = fmap[key]; }
  }
  if (p != null) {
    if (!isa(p, $outline_item)) { raise { code: "E_INVARG", message: "parent must be an outline item", value: p }; }
    if (location(p) != this) { raise { code: "E_INVARG", message: "parent is not in this outliner", value: p }; }
  }
  // Bounded read: the owner-computed ordered children of `p` (rows carry ranks).
  let rows = ordered_children(p);
  let n = length(rows);
  let idx = index;
  if (typeof(idx) != "number") { idx = n; }
  idx = floor(idx);
  if (idx < 0 || idx > n) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, n: n } }; }
  // Neighbour ranks at the insert slot; one fractional rank strictly between.
  let lo = null; let hi = null;
  if (idx > 0) { lo = rows[idx]["rank"]; }
  if (idx < n) { hi = rows[idx + 1]["rank"]; }
  let rank = rank_between(lo, hi);
  // Room-anchored item (create sets anchor = this outliner's scope), then ONE
  // authored edge cell. No contents scan, no renumber.
  let item = create($outline_item, { owner: actor, location: this, name: "" });
  item.__ordered_edge = { parent: p, rank: rank };
  item:set_text(text);
  observe({ type: "outline_item_added", source: this, actor: actor, outliner: this, item: item, parent_id: p, index: idx, text: text, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "remove_item", args: [item] });
  }
  return item;
}

verb :set_item_text(item, text, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  let old_text = "";
  try { old_text = item.text; } except err { old_text = ""; }
  item:set_text(text);
  if (!_no_store) {
    this:_set_undo(actor, { verb: "set_item_text", args: [item, old_text] });
  }
  return true;
}

verb :move_item(item, new_parent_id, index, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (new_parent_id != null) {
    if (!isa(new_parent_id, $outline_item)) { raise { code: "E_INVARG", message: "parent must be outline item or null", value: new_parent_id }; }
    if (location(new_parent_id) != this) { raise { code: "E_INVARG", message: "parent is in a different outliner", value: new_parent_id }; }
    if (new_parent_id == item) { raise { code: "E_CYCLE", message: "item cannot be its own parent", value: item }; }
    // Cycle guard: walk the new parent's ancestor edges (bounded by depth).
    let pe = new_parent_id.__ordered_edge; let pp = null;
    if (typeof(pe) == "map") { pp = pe["parent"]; }
    while (pp != null) {
      if (pp == item) { raise { code: "E_CYCLE", message: "cycle detected", value: { item: item, parent: new_parent_id } }; }
      let ge = pp.__ordered_edge; let gp = null;
      if (typeof(ge) == "map") { gp = ge["parent"]; }
      pp = gp;
    }
  }
  // Old parent + old index (for the observation + undo), from the item's edge.
  let oe = item.__ordered_edge; let old_parent = null;
  if (typeof(oe) == "map") { old_parent = oe["parent"]; }
  let old_rows = ordered_children(old_parent);
  let old_idx = 0; let i = 0;
  for r in old_rows { if (r["child"] == item) { old_idx = i; } i = i + 1; }
  let cross = (new_parent_id != old_parent);
  let dest_rows = old_rows;
  if (cross) { dest_rows = ordered_children(new_parent_id); }
  // Neighbour list excludes the moving item.
  let dest = [];
  for r in dest_rows { if (r["child"] != item) { dest = dest + [r]; } }
  let max_idx = length(dest);
  let idx = index;
  if (typeof(idx) != "number") { idx = max_idx; }
  idx = floor(idx);
  if (idx < 0 || idx > max_idx) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, max: max_idx } }; }
  if (!cross && idx == old_idx) { return false; }
  let lo = null; let hi = null;
  if (idx > 0) { lo = dest[idx]["rank"]; }
  if (idx < max_idx) { hi = dest[idx + 1]["rank"]; }
  let rank = rank_between(lo, hi);
  // ONE edge rewrite; the old-parent siblings keep their ranks (no renumber).
  item.__ordered_edge = { parent: new_parent_id, rank: rank };
  observe({ type: "outline_item_moved", source: this, actor: actor, outliner: this, item: item, from_parent: old_parent, from_index: old_idx, to_parent: new_parent_id, to_index: idx, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "move_item", args: [item, old_parent, old_idx] });
  }
  return true;
}

verb :reorder_item(item, index, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  let oe = item.__ordered_edge; let parent_id = null;
  if (typeof(oe) == "map") { parent_id = oe["parent"]; }
  let rows = ordered_children(parent_id);
  let old_idx = 0; let i = 0;
  for r in rows { if (r["child"] == item) { old_idx = i; } i = i + 1; }
  let without = [];
  for r in rows { if (r["child"] != item) { without = without + [r]; } }
  let max_idx = length(without);
  let idx = index;
  if (typeof(idx) != "number") { raise { code: "E_INVARG", message: "reorder_item requires an index", value: idx }; }
  idx = floor(idx);
  if (idx < 0 || idx > max_idx) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, max: max_idx } }; }
  if (idx == old_idx) { return false; }
  let lo = null; let hi = null;
  if (idx > 0) { lo = without[idx]["rank"]; }
  if (idx < max_idx) { hi = without[idx + 1]["rank"]; }
  let rank = rank_between(lo, hi);
  item.__ordered_edge = { parent: parent_id, rank: rank };
  observe({ type: "outline_item_reordered", source: this, actor: actor, outliner: this, item: item, parent_id: parent_id, from_index: old_idx, to_index: idx, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "reorder_item", args: [item, old_idx] });
  }
  return true;
}

verb :hide(item, hidden, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (typeof(hidden) != "boolean") {
    if (hidden == 0) { hidden = false; } else { if (hidden == 1) { hidden = true; } else { raise { code: "E_INVARG", message: "hide requires a boolean", value: hidden }; } }
  }
  let was = false;
  try { was = item.hidden; } except err { was = false; }
  item:set_hidden(hidden);
  observe({ type: "outline_item_hidden", source: this, actor: actor, outliner: this, item: item, hidden: hidden, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "hide", args: [item, was] });
  }
  return true;
}

verb :hide_command(item) rx {
  let target = item;
  if (typeof(target) == "string") { target = $match:match_object(target, this); }
  if (target == $failed_match || target == $ambiguous_match) { raise { code: "E_INVARG", message: "hide which item?", value: item }; }
  return this:hide(target, true);
}

verb :remove_item(item, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (item.owner != actor && !has_flag(actor, "wizard")) { raise { code: "E_PERM", message: "only the item author or a wizard can remove it; outliner owners use eject", value: item }; }
  // Capture state for undo.
  let captured = this:_capture_item(item);
  recycle(item);
  if (!_no_store) {
    this:_set_undo(actor, { verb: "_restore_item", args: [captured] });
  }
  return true;
}

verb :eject_item(item) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (this.owner != actor && !has_flag(actor, "wizard")) { raise { code: "E_PERM", message: "only the outliner owner or a wizard can eject items", value: item }; }
  // No undo for curator path.
  recycle(item);
  return true;
}

verb :_capture_item(item) rx {
  let e = item.__ordered_edge; let ep = null;
  if (typeof(e) == "map") { ep = e["parent"]; }
  let rows = ordered_children(ep);
  let idx = 0; let i = 0;
  for r in rows { if (r["child"] == item) { idx = i; } i = i + 1; }
  let kids = ordered_children(item);
  let kid_entries = [];
  let ki = 0;
  for kr in kids {
    kid_entries = kid_entries + [{ item: kr["child"], index: ki }];
    ki = ki + 1;
  }
  let text = "";
  try { text = item.text; } except err { text = ""; }
  let writers = [];
  try { writers = item.writers; } except err { writers = []; }
  let hidden = false;
  try { hidden = item.hidden; } except err { hidden = false; }
  return {
    text: text,
    name: item.name,
    description: item.description,
    writers: writers,
    hidden: hidden,
    owner: item.owner,
    parent_id: ep,
    index: idx,
    children: kid_entries
  };
}

verb :undo() rx {
  let key = to_string(actor);
  let umap = this.last_undo;
  if (!has(umap, key)) { return false; }
  let record = umap[key];
  if (record == null) { return false; }
  // Clear slot before dispatch so the dispatched verb doesn't re-write it.
  let next = {};
  for k in keys(umap) { if (k != key) { next[k] = umap[k]; } }
  this.last_undo = next;
  let verb_name = record["verb"];
  let inverse_args = record["args"];
  // Append the no-store marker so dispatched composers skip slot writes.
  let full_args = [];
  for a in inverse_args { full_args = full_args + [a]; }
  full_args = full_args + [true];
  let result = null;
  try { result = dispatch(this, verb_name, full_args); } except err {
    observe({ type: "outline_undone", source: this, actor: actor, outliner: this, inverse_op: record, error: err, ts: now() });
    return false;
  }
  observe({ type: "outline_undone", source: this, actor: actor, outliner: this, inverse_op: record, ts: now() });
  return result;
}

verb :focus_on(item) rx {
  let target = null;
  if (item != null) {
    if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "focus target must be null or an outline item", value: item }; }
    if (location(item) != this) { raise { code: "E_NO_ITEM", message: "focus target is not in this outliner", value: item }; }
    target = item;
  }
  let key = to_string(actor);
  let fmap = this.focus_by_actor;
  let next = {};
  let present_keys = {};
  for compact in room_roster(this) { present_keys[to_string(compact["player"])] = true; }
  for k in keys(fmap) {
    if (k != key && has(present_keys, k)) { next[k] = fmap[k]; }
  }
  next[key] = target;
  this.focus_by_actor = next;
  observe({ type: "outline_focus_changed", source: this, actor: actor, to: actor, outliner: this, item: target, ts: now() });
  return target;
}

verb :focus_command(item) rx {
  let target = item;
  if (typeof(target) == "string") { target = $match:match_object(target, this); }
  if (target == $failed_match || target == $ambiguous_match) { raise { code: "E_INVARG", message: "focus which item?", value: item }; }
  return this:focus_on(target);
}

verb :add(text) rx {
  if (typeof(text) != "string") { raise { code: "E_INVARG", message: "add requires text", value: text }; }
  text = str_trim(text);
  if (text == "") { raise { code: "E_INVARG", message: "add requires non-empty text", value: text }; }
  return this:add_item(text);
}
